mapper.select:
SELECT a.gvrnr_uid, a.gvrnr_press1::float AS gvrnr_press1, a.gvrnr_press2::float AS gvrnr_press2, a.gvrnr_trnsps1, a.gvrnr_trnsps2, to_char(a.record_dttm, 'YYYY-MM-DD HH24:MI:SS') AS record_dttm FROM t_governor_stat a INNER JOIN generate_series( CAST(#{startDate} AS TIMESTAMP), CAST(#{endDate} AS DATE) + INTERVAL '1 day' - INTERVAL '1 minute', CAST(#{intervalNum} AS INTEGER) * INTERVAL '1 minute' ) interval_dttm ON a.record_dttm = interval_dttm WHERE a.record_dttm >= CAST(#{startDate} AS DATE) AND a.record_dttm < CAST(#{endDate} AS DATE) + INTERVAL '1 day'
#{uid}
ORDER BY a.record_dttm ASC, a.gvrnr_uid ASC
